#!/usr/bin/env perl
use strict;
use warnings;
use File::Path qw(make_path);
use File::Copy;
use File::Basename;
use Digest::SHA qw(sha1_hex);
use Fcntl qw(:SEEK);

my $MINIGIT_DIR = '.minigit';
my $OBJECTS_DIR = "$MINIGIT_DIR/objects";
my $REFS_DIR = "$MINIGIT_DIR/refs";
my $HEAD_FILE = "$MINIGIT_DIR/HEAD";
my $INDEX_FILE = "$MINIGIT_DIR/index";

sub init {
    make_path($OBJECTS_DIR, $REFS_DIR);
    open my $fh, '>', $HEAD_FILE or die "Cannot create HEAD: $!";
    print $fh "ref: refs/heads/main\n";
    close $fh;
    open $fh, '>', $INDEX_FILE or die "Cannot create index: $!";
    close $fh;
    print "Initialized empty minigit repository\n";
}

sub get_hash {
    my ($content) = @_;
    return sha1_hex($content);
}

sub store_object {
    my ($content) = @_;
    my $hash = get_hash($content);
    my $dir = "$OBJECTS_DIR/" . substr($hash, 0, 2);
    my $file = "$dir/" . substr($hash, 2);
    make_path($dir) unless -d $dir;
    open my $fh, '>', $file or die "Cannot write object: $!";
    print $fh $content;
    close $fh;
    return $hash;
}

sub load_object {
    my ($hash) = @_;
    my $file = "$OBJECTS_DIR/" . substr($hash, 0, 2) . "/" . substr($hash, 2);
    open my $fh, '<', $file or die "Cannot read object: $!";
    local $/;
    my $content = <$fh>;
    close $fh;
    return $content;
}

sub hash_object {
    my ($file) = @_;
    open my $fh, '<', $file or die "Cannot open $file: $!";
    local $/;
    my $content = <$fh>;
    close $fh;
    my $hash = store_object($content);
    print "$hash\n";
}

sub read_index {
    my %index;
    if (-e $INDEX_FILE) {
        open my $fh, '<', $INDEX_FILE or die "Cannot read index: $!";
        while (<$fh>) {
            chomp;
            my ($hash, $path) = split ' ', $_, 2;
            $index{$path} = $hash;
        }
        close $fh;
    }
    return \%index;
}

sub write_index {
    my ($index) = @_;
    open my $fh, '>', $INDEX_FILE or die "Cannot write index: $!";
    for my $path (sort keys %$index) {
        print $fh "$index->{$path} $path\n";
    }
    close $fh;
}

sub add {
    my @files = @_;
    my $index = read_index();
    for my $file (@files) {
        open my $fh, '<', $file or die "Cannot open $file: $!";
        local $/;
        my $content = <$fh>;
        close $fh;
        my $hash = store_object($content);
        $index->{$file} = $hash;
    }
    write_index($index);
}

sub ls_files {
    my $index = read_index();
    for my $path (sort keys %$index) {
        print "$index->{$path} $path\n";
    }
}

sub get_current_branch {
    open my $fh, '<', $HEAD_FILE or die "Cannot read HEAD: $!";
    my $line = <$fh>;
    close $fh;
    chomp $line;
    if ($line =~ /^ref: (.+)$/) {
        return $1;
    }
    return undef;
}

sub get_ref_hash {
    my ($ref) = @_;
    my $file = "$MINIGIT_DIR/$ref";
    if (-e $file) {
        open my $fh, '<', $file or die "Cannot read ref: $!";
        my $hash = <$fh>;
        close $fh;
        chomp $hash;
        return $hash;
    }
    return undef;
}

sub set_ref_hash {
    my ($ref, $hash) = @_;
    my $file = "$MINIGIT_DIR/$ref";
    make_path(dirname($file));
    open my $fh, '>', $file or die "Cannot write ref: $!";
    print $fh "$hash\n";
    close $fh;
}

sub create_commit_tree {
    my ($index) = @_;
    my @entries;
    for my $path (sort keys %$index) {
        my $hash = $index->{$path};
        push @entries, "100644 $hash\t$path";
    }
    my $tree = join("\n", @entries) . "\n";
    return store_object($tree);
}

sub read_commit_tree {
    my ($tree_hash) = @_;
    my $tree = load_object($tree_hash);
    my %tree;
    for my $line (split /\n/, $tree) {
        next unless $line;
        my ($mode, $hash, $path) = split /\s+/, $line, 3;
        $tree{$path} = $hash;
    }
    return \%tree;
}

sub commit {
    my ($message) = @_;
    my $index = read_index();
    my $tree_hash = create_commit_tree($index);
    my $parent;
    my $current_branch = get_current_branch();
    if ($current_branch) {
        $parent = get_ref_hash($current_branch);
    }
    my $commit = "tree $tree_hash\n";
    $commit .= "parent $parent\n" if $parent;
    $commit .= "author minigit\n";
    $commit .= "committer minigit\n";
    $commit .= "\n$message\n";
    my $commit_hash = store_object($commit);
    if ($current_branch) {
        set_ref_hash($current_branch, $commit_hash);
    } else {
        set_ref_hash('refs/heads/main', $commit_hash);
    }
    print "Commit $commit_hash\n";
}

sub get_commit {
    my ($hash) = @_;
    my $commit = load_object($hash);
    my %data;
    for my $line (split /\n/, $commit) {
        if ($line =~ /^tree ([a-f0-9]{40})$/) {
            $data{tree} = $1;
        } elsif ($line =~ /^parent ([a-f0-9]{40})$/) {
            $data{parent} = $1;
        } elsif ($line eq '') {
            last;
        }
    }
    return \%data;
}

sub checkout {
    my ($hash) = @_;
    my $index = read_index();
    my $tree_hash;
    if (length($hash) == 40) {
        $tree_hash = $hash;
    } else {
        my $ref = "refs/heads/$hash";
        $hash = get_ref_hash($ref);
        die "Unknown ref $ref" unless $hash;
        my $commit = get_commit($hash);
        $tree_hash = $commit->{tree};
    }
    my $tree = read_commit_tree($tree_hash);
    for my $path (keys %$tree) {
        my $hash = $tree->{$path};
        my $content = load_object($hash);
        open my $fh, '>', $path or die "Cannot write $path: $!";
        print $fh $content;
        close $fh;
    }
    $index = {};
    for my $path (keys %$tree) {
        $index->{$path} = $tree->{$path};
    }
    write_index($index);
    if (my $ref = get_current_branch()) {
        set_ref_hash($ref, $hash);
    } else {
        set_ref_hash('refs/heads/main', $hash);
    }
    print "Checked out $hash\n";
}

sub log {
    my ($hash) = @_;
    $hash = get_ref_hash(get_current_branch()) unless $hash;
    while ($hash) {
        print "$hash\n";
        my $commit = get_commit($hash);
        $hash = $commit->{parent};
    }
}

sub diff {
    my ($hash) = @_;
    my $index = read_index();
    my $tree_hash;
    if ($hash) {
        if (length($hash) == 40) {
            $tree_hash = $hash;
        } else {
            my $ref = "refs/heads/$hash";
            $hash = get_ref_hash($ref);
            die "Unknown ref $ref" unless $hash;
            my $commit = get_commit($hash);
            $ = $commit->{tree};
        }
    } else {
        $tree_hash = get_ref_hash(get_current_branch());
        if ($tree_hash) {
            my $commit = get_commit($tree_hash);
            $tree_hash = $commit->{tree};
        }
    }
    my $tree = $tree_hash ? read_commit_tree($tree_hash) : {};
    my %all_files;
    for my $file (keys %$index) {
        $all_files{$file} = 1;
    }
    for my $file (keys %$tree) {
        $all_files{$file} = 1;
    }
    for my $file (sort keys %all_files) {
        my $index_hash = $index->{$file};
        my $tree_hash = $tree->{$file};
        if (!$index_hash) {
            print "deleted: $file\n";
        } elsif (!$tree_hash) {
            print "new: $file\n";
        } elsif ($index_hash ne $tree_hash) {
            print "modified: $file\n";
        }
    }
}

my $command = shift @ARGV;
if ($command eq 'init') {
    init();
} elsif ($command eq 'hash-object') {
    my $file = shift @ARGV;
    hash_object($file);
} elsif ($command eq 'add') {
    add(@ARGV);
} elsif ($command eq 'ls-files') {
    ls_files();
} elsif ($command eq 'commit') {
    my $message = shift @ARGV;
    commit($message);
} elsif ($command eq 'checkout') {
    my $hash = shift @ARGV;
    checkout($hash);
} elsif ($command eq 'log') {
    my $hash = shift @ARGV;
    log($hash);
} elsif ($command eq 'diff') {
    my $hash = shift @ARGV;
    diff($hash);
} else {
    die "Unknown command: $command";
}
